insert into blocks (site_slug, section, kind, position, data) values ('arcade', 'lede', 'lede', 2, '{"html":"Five machines, five interaction grammars, zero loot boxes. Each one makes a claim about how your life actually works — then hands you the controls and lets you <b>lose to your own habits</b> in a safe, well-lit room. Cheaper than the real-world version. Significantly faster feedback."}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('arcade', 'play', 'kv', 3, '{"label":"PLAY →","hrefs":{"leap":"/m/leap","bedtime":"/m/bedtime","plate":"/m/plate","cascade":"/m/cascade","tax":"/m/tax","rupee":"/m/rupee"}}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('arcade', 'scores', 'kv', 4, '{"k":"TODAY''S HIGH SCORES","rows":[["PEOPLE WHO BEAT THE GLUCOSE CURVE","3"],["PEOPLE WHO QUIT IN MONTH ONE (SIMULATED)","412"],["PEOPLE WHO QUIT IN MONTH ONE (REAL)","0 — THAT''S THE POINT"],["MEETINGS DECLINED AFTER PLAYING THE TAX","COUNTING"]]}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('arcade', 'capture', 'kv', 5, '{"k":"ONE NEW MACHINE A MONTH.","sub":"No essays, just the cartridge.","placeholder":"your@address","button":"SUBSCRIBE","ok":"Noted. One cartridge a month.","err":"Didn''t take. Try again."}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('arcade', 'studio', 'kv', 6, '{"k":"COMMISSION A MACHINE","body":"I build the playable version of your course/book''s core idea. White-label, your domain, two-week turnaround.","cta":{"label":"operator.zephyrcode.live/commission →","href":"https://operator.zephyrcode.live/commission"}}'::jsonb);
delete from sims;
insert into sims (slug, name, grammar, blurb, position) values ('leap', 'THE LEAP', 'GRAMMAR · DRAG THE FUTURE', 'Drag the month you quit your job. Watch the valley floor rise — or not — to meet you.', 1);
insert into sims (slug, name, grammar, blurb, position) values ('bedtime', 'BEDTIME', 'GRAMMAR · SWIPE & SUFFER', 'A dilemma deck with four meters that remember exactly what you chose at 9:47pm.', 2);
insert into sims (slug, name, grammar, blurb, position) values ('plate', 'THE PLATE', 'GRAMMAR · DIRECT MANIPULATION', 'Build the meal with your hands; the glucose curve answers in real time. The curve is honest. Brutally.', 3);
insert into sims (slug, name, grammar, blurb, position) values ('cascade', 'CASCADE', 'GRAMMAR · AGENTS, RELEASED', 'How ideas actually spread — simple contagion versus the complex kind that needs three friends and a nudge.', 4);
insert into sims (slug, name, grammar, blurb, position) values ('tax', 'THE INTERRUPTION TAX', 'GRAMMAR · THE LEDGER', 'What one "quick meeting" really costs a maker''s afternoon. Bring a strong stomach.', 5);
insert into sims (slug, name, grammar, blurb, position) values ('rupee', 'EVERY RUPEE A JOB', 'GRAMMAR · THE ASSIGNMENT', 'Pile up everything you own; line up everything you want. The machine assigns each asset its job — and names the salary you''re missing.', 6);
insert into sites (slug, host, title, description, accent, og_image, nav_order) values ('read', 'read.zephyrcode.live', 'READ — the shelf with a temperature · ZephyrCode', 'Fourteen books on a single heat gradient — from Dinkar''s war drums to the dissolving quiet of The Book of Mirdad. Pick by the day you''re having, not the canon you''re told.', '#E85D2A', null, 6) on conflict (slug) do update set host=excluded.host, title=excluded.title, description=excluded.description, accent=excluded.accent, og_image=excluded.og_image, nav_order=excluded.nav_order;
delete from blocks where site_slug = 'read';
insert into blocks (site_slug, section, kind, position, data) values ('read', 'top', 'crumb', 1, '{"text":"READ · FIRE → STILLNESS"}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('read', 'hero', 'heading', 2, '{"eyebrow":"read.zephyrcode.live","h1Html":"The shelf with <em>a temperature.</em>","ledeHtml":"Fourteen books on one axis — <b>fire to stillness</b>, Dinkar''s war drums to the dissolving quiet of Mirdad. Genre is a librarian''s problem. The only real question is what the day is asking for. Set the dial; the shelf answers."}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('read', 'dial', 'dial', 3, '{"fire":"FIRE — pre-training, pre-war, pre-deadline","still":"STILL — after, and above","ariaLabel":"Mood: fire to stillness","askLines":[[0,"the day wants drums. the shelf agrees."],[25,"voltage with a spine. musashi is watching your posture."],[45,"the bridge: burn, but without smoke."],[65,"the emperor and the poet pour you something."],[82,"breathe out. the arguments are dissolving."],[101,""]]}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('read', 'start', 'picks', 4, '{"k":"START THIS WEEK · THE FOUR-BOOK IGNITION","picks":[["Rashmirathi","THE CENTER OF GRAVITY"],["The Book of Five Rings","THE TRAINING PARTNER"],["Bhagavad Gita","THE HINGE"],["Siddhartha","THE EXHALE"]],"tail":"Read the fire standing up and the stillness sitting down. There is no third posture; that''s the whole curriculum."}'::jsonb);
delete from books;
insert into books (position, title, author, pos, register, lang, note) values (1, 'Haldighati', 'Shyam Narayan Pandey', 0.02, 'FIRE', 'HINDI', 'Hooves, steel, and a horse that out-acts most protagonists. Pure veer rasa, zero apologies.');
insert into books (position, title, author, pos, register, lang, note) values (2, 'Rashmirathi', 'Ramdhari Singh Dinkar', 0.07, 'FIRE', 'HINDI', 'Karna''s answer to the accident of birth, delivered at sword-length. Krishna''s warning canto alone is worth the shelf. Start here.');
insert into books (position, title, author, pos, register, lang, note) values (3, 'Parashuram ki Prateeksha', 'Dinkar', 0.12, 'FIRE', 'HINDI', 'A nation scolded awake after 1962. Reads like a slap that loves you.');
insert into books (position, title, author, pos, register, lang, note) values (4, 'Ram ki Shakti Puja', 'Suryakant Tripathi ''Nirala''', 0.18, 'FIRE', 'HINDI', 'Even gods rehearse. Ram confronting his own weakness on the eve of war — dense, towering, worth the climb.');
insert into books (position, title, author, pos, register, lang, note) values (5, 'Hunkar', 'Dinkar', 0.22, 'FIRE', 'HINDI', 'The warm-up drum. Short blasts of voltage for mornings that start heavy.');
insert into books (position, title, author, pos, register, lang, note) values (6, 'The Book of Five Rings', 'Musashi · tr. Cleary', 0.28, 'FIRE', 'EN', 'Sixty duels undefeated, and his deepest advice is about attention. Talks straight to the gloves. Reread yearly.');
insert into books (position, title, author, pos, register, lang, note) values (7, 'Thus Spoke Zarathustra', 'Friedrich Nietzsche', 0.34, 'FIRE', 'EN · HARD', 'Osho''s number one. Prose-poetry that bites if grabbed — read in passages, like lifting, never to failure.');
insert into books (position, title, author, pos, register, lang, note) values (8, 'Kurukshetra', 'Dinkar', 0.45, 'BRIDGE', 'HINDI', 'Violence cross-examined on a bed of arrows. Where the fire poems start asking questions.');
insert into books (position, title, author, pos, register, lang, note) values (9, 'Bhagavad Gita', 'tr. Eknath Easwaran', 0.52, 'BRIDGE', 'EN', 'A warrior talked back into the fight and taught to burn without smoke. If you read one book off this shelf, this.');
insert into books (position, title, author, pos, register, lang, note) values (10, 'Meditations', 'Marcus Aurelius', 0.62, 'BRIDGE', 'EN', 'An emperor''s private notes on not becoming the thing he ruled. Written for an audience of one; somehow about you.');
insert into books (position, title, author, pos, register, lang, note) values (11, 'Madhushala', 'Harivansh Rai Bachchan', 0.68, 'BRIDGE', 'HINDI', 'Intoxication as theology. Sip, don''t gulp — every quatrain is a full pour.');
insert into books (position, title, author, pos, register, lang, note) values (12, 'Siddhartha', 'Hermann Hesse', 0.78, 'STILL', 'EN · EASY', 'Enlightenment by way of everything the monks renounce. The warm door into the quiet wing.');
insert into books (position, title, author, pos, register, lang, note) values (13, 'Enlightenment: The Only Revolution', 'Osho on Ashtavakra', 0.86, 'STILL', 'EN', 'The hammer that whispers: you are already free — stop applying. One discourse at a time, preferably horizontal.');
insert into books (position, title, author, pos, register, lang, note) values (14, 'The Book of Mirdad', 'Mikhail Naimy', 0.95, 'STILL', 'EN · SHORT', 'The quiet book that ends arguments by dissolving the arguer. Why Osho is Osho.');
insert into sites (slug, host, title, description, accent, og_image, nav_order) values ('watch', 'watch.zephyrcode.live', 'WATCH — eight mood channels · ZephyrCode', 'Series and films sorted by state of mind, not genre — from Brain on Fire to Decompress. Scored against one viewer''s taste profile, ranked without mercy.', '#C9A45C', null, 7) on conflict (slug) do update set host=excluded.host, title=excluded.title, description=excluded.description, accent=excluded.accent, og_image=excluded.og_image, nav_order=excluded.nav_order;
