insert into blocks (site_slug, section, kind, position, data) values ('watch', 'hero', 'hero', 1, '{"eyebrow":"watch.zephyrcode.live","h1":"Eight channels. <em>Zero browsing.</em>","lede":"Streaming menus answer \"what exists.\" This answers <b>\"what is tonight for?\"</b> Every title is scored against one viewer''s taste profile — cerebral mystery, hard SF with a pulse, crime with a conscience — and ranked without mercy. <b>Dark</b> is the north star. It was always going to be."}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('watch', 'np', 'kv', 2, '{"tunedPrefix":"NOW TUNED · CH","footnote":"MATCH % = FIT TO THE HOUSE TASTE PROFILE, NOT QUALITY. QUALITY IS ASSUMED; WE DON''T SHELVE FILLER.","aria":"Mood channels"}'::jsonb);
