insert into watch_titles (channel_id, title, match, platform, why, position) select ch.id, t.* from ch, (values ('Dark', 99::int, 'NETFLIX', 'Three generations, one cave, zero wasted scenes. The reference standard — watched five times in this house, still undefeated.', 1::int), ('Bodies', 94::int, 'NETFLIX', 'One corpse, four detectives, four timelines. A loop that actually closes.', 2::int), ('3 Body Problem', 92::int, 'NETFLIX', 'Physics breaks first; people follow. Read the trilogy and feel superior, gently.', 3::int)) as t(title, match, platform, why, position);
