insert into watch_titles (channel_id, title, match, platform, why, position) select ch.id, t.* from ch, (values ('My Name', 91::int, 'NETFLIX', 'Revenge with footwork. The fight choreography respects your training eye.', 1::int), ('The Night Comes for Us', 88::int, 'NETFLIX', 'Indonesian action at maximum honesty. Stretch first.', 2::int), ('Extraction', 84::int, 'NETFLIX', 'One-take logistics. Cardio for the camera operator.', 3::int)) as t(title, match, platform, why, position);
with ch as (insert into watch_channels (n, name, tagline, position) values ('04', 'Shadow Games', 'spies, leaks, long knives', 4) returning id)
insert into watch_titles (channel_id, title, match, platform, why, position) select ch.id, t.* from ch, (values ('The Family Man', 95::int, 'PRIME', 'Middle management versus national security. The most honest job description on television.', 1::int), ('Slow Horses', 93::int, 'ATV+', 'Failed spies, magnificent spite. Lamb is a one-man counterargument to LinkedIn.', 2::int), ('The Night Manager', 87::int, 'JIO', 'Le Carré with better hotels. Treachery, beautifully lit.', 3::int)) as t(title, match, platform, why, position);
with ch as (insert into watch_channels (n, name, tagline, position) values ('05', 'Statecraft', 'power, watched closely', 5) returning id)
insert into watch_titles (channel_id, title, match, platform, why, position) select ch.id, t.* from ch, (values ('Scam 1992', 94::int, 'SONY', 'A market, a man, a margin call on an entire system. Rewatch material for systems thinkers.', 1::int), ('The Diplomat', 88::int, 'NETFLIX', 'Crisis management as bloodsport. Dialogue with elbows.', 2::int), ('House of Cards', 85::int, 'NETFLIX', 'The machinery of ambition, fourth wall optional. Early seasons, then exit clean.', 3::int)) as t(title, match, platform, why, position);
with ch as (insert into watch_channels (n, name, tagline, position) values ('06', 'Slow Descent', 'beautiful unravelings', 6) returning id)
insert into watch_titles (channel_id, title, match, platform, why, position) select ch.id, t.* from ch, (values ('Severance', 96::int, 'ATV+', 'Work-life balance, surgically enforced. The most elegant horror premise of the decade.', 1::int), ('Mr. Robot', 93::int, 'PRIME', 'An unreliable narrator with root access. Society gets debugged; so does he.', 2::int), ('The OA', 90::int, 'NETFLIX', 'Faith, movement, and a swing for the fences that connects. Yes, even the ending.', 3::int)) as t(title, match, platform, why, position);
with ch as (insert into watch_channels (n, name, tagline, position) values ('07', 'Prestige & Page', 'novels that learned to act', 7) returning id)
insert into watch_titles (channel_id, title, match, platform, why, position) select ch.id, t.* from ch, (values ('Shōgun', 96::int, 'JIO', 'Power as language lesson. Every silence is load-bearing.', 1::int), ('Pachinko', 95::int, 'ATV+', 'Four generations carried across water. Television that earns the word literature.', 2::int), ('The Queen''s Gambit', 91::int, 'NETFLIX', 'Genius as addiction with better lighting. The ceiling scene alone.', 3::int)) as t(title, match, platform, why, position);
with ch as (insert into watch_channels (n, name, tagline, position) values ('08', 'Decompress', 'low stakes, high craft', 8) returning id)
insert into watch_titles (channel_id, title, match, platform, why, position) select ch.id, t.* from ch, (values ('Our Planet', 86::int, 'NETFLIX', 'Attenborough administers perspective. The only feed worth doomscrolling.', 1::int), ('Chef''s Table', 84::int, 'NETFLIX', 'Obsession, plated. Watch a master descend, compress, animate, ship — sound familiar?', 2::int), ('Ted Lasso', 88::int, 'ATV+', 'Sincerity played as a power move. Recovery content for cynics.', 3::int)) as t(title, match, platform, why, position);
insert into sites (slug, host, title, description, accent, og_image, nav_order) values ('listen', 'listen.zephyrcode.live', 'LISTEN — the listening room · ZephyrCode', 'Five things a rig must prove — weight, stage, breath, detail, dynamics — and the tracks that interrogate each one. Reference chain: HD 660S2 into a FiiO K11 R2R, balanced, high gain.', '#E85D2A', null, 8) on conflict (slug) do update set host=excluded.host, title=excluded.title, description=excluded.description, accent=excluded.accent, og_image=excluded.og_image, nav_order=excluded.nav_order;
delete from blocks where site_slug = 'listen';
insert into blocks (site_slug, section, kind, position, data) values ('listen', 'hero', 'hero', 1, '{"eyebrow":"listen.zephyrcode.live","h1":"Five things a rig <em>must prove.</em>","lede":"Specifications are testimony; <b>music is cross-examination.</b> Below: the five proofs every chain in this house has to pass, the tracks that interrogate each one, and the scope showing what you should be hearing. No burn-in ritual required — <b>your ears do the burning-in.</b>"}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('listen', 'scope', 'kv', 2, '{"labPrefix":"PROOF ","hzLine":"REFERENCE TRACE · NOT TO SCALE · OBVIOUSLY","aria":"The five proofs"}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('listen', 'ignition', 'kv', 3, '{"k":"BONUS PROOF · IGNITION","t":"DIVINE · Seedhe Maut · gym volume","s":"THE IEM DEPARTMENT (ZERO:RED) HANDLES GLOVES-ON HOURS. THE HEADPHONES STAY HOME AND JUDGE."}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('listen', 'rig', 'kv', 4, '{"k":"THE RIG OF RECORD","chain":["SOURCE · LOSSLESS","FiiO K11 R2R","4.4mm BALANCED","SENNHEISER HD 660S2","STERNUM"],"note":"High gain, volume at \"respectful.\" R2R because numbers should pass through a ladder of actual resistors before becoming feelings. The truth-teller screen reads 44.1 when the stream behaves, and you check it the way other people check the weather. <b>Mobile detachment:</b> ZERO:RED IEMs off a ddHiFi dongle — the away kit for a rig that took the home game seriously."}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('listen', 'crumb', 'label', 5, '{"text":"LISTEN · THE LISTENING ROOM"}'::jsonb);
delete from listen_tracks;
delete from listen_proofs;
with pf as (insert into listen_proofs (n, name, claim, voices, position) values ('01', 'WEIGHT', 'Bass you feel in the sternum, not the eardrum. If the room doesn''t get heavier, return the cable.', '[{"c":"#E85D2A","w":2.5,"f":1.6,"a":52,"sp":0.9,"sub":0.5}]'::jsonb, 1) returning id)
insert into listen_tracks (proof_id, title, artist, why, position) select pf.id, t.* from pf, (values ('Why So Serious?', 'Hans Zimmer', 'The famous low-end descent — a structural inspection for your floor, your seal, your resolve.', 1::int), ('Angel', 'Massive Attack', 'A bassline with a predator''s patience. Texture down where most rigs only rumble.', 2::int)) as t(title, artist, why, position);
with pf as (insert into listen_proofs (n, name, claim, voices, position) values ('02', 'STAGE', 'Close your eyes; the band should have coordinates. Width is easy — depth is the tell.', '[{"c":"#E85D2A","w":2,"f":2.4,"a":34,"sp":1.1,"ph":0,"off":-22},{"c":"#C9A45C","w":2,"f":2.4,"a":34,"sp":1.1,"ph":2.1,"off":22}]'::jsonb, 2) returning id)
insert into listen_tracks (proof_id, title, artist, why, position) select pf.id, t.* from pf, (values ('Bubbles', 'Yosi Horikawa', 'Field recordings that place each droplet at an address. Imaging''s party trick, performed straight-faced.', 1::int), ('Time', 'Hans Zimmer', 'One phrase, twelve entrances. Count the layers arriving; lose count on purpose.', 2::int)) as t(title, artist, why, position);
with pf as (insert into listen_proofs (n, name, claim, voices, position) values ('03', 'BREATH', 'The air between notes — decay, room, the intake before the line. Intimacy is a resolution problem.', '[{"c":"#C9A45C","w":2,"f":3.2,"a":22,"sp":0.7,"noise":9}]'::jsonb, 3) returning id)
insert into listen_tracks (proof_id, title, artist, why, position) select pf.id, t.* from pf, (values ('Apocalypse', 'Cigarettes After Sex', 'Reverb tails you could sleep in. The vocal sits close enough to be a confession.', 1::int), ('Riverside', 'Agnes Obel', 'Felt on hammers, floorboards under pedals. You can hear the room thinking.', 2::int)) as t(title, artist, why, position);
with pf as (insert into listen_proofs (n, name, claim, voices, position) values ('04', 'DETAIL', 'What survives at low volume is the truth of a chain. Texture at the edge of silence.', '[{"c":"#E85D2A","w":1.6,"f":2,"a":26,"sp":0.8,"ripF":22,"ripA":7}]'::jsonb, 4) returning id)
insert into listen_tracks (proof_id, title, artist, why, position) select pf.id, t.* from pf, (values ('Hand Covers Bruise', 'Trent Reznor & Atticus Ross', 'A piano decaying over a noise floor that slowly tells the truth about your DAC.', 1::int), ('Says', 'Nils Frahm', 'One arpeggio, ten patient minutes, the swell of the decade. Detail becomes weather.', 2::int)) as t(title, artist, why, position);
with pf as (insert into listen_proofs (n, name, claim, voices, position) values ('05', 'DYNAMICS', 'The quiet must be honest so the loud can be violent. Warn the household; apologize to no one.', '[{"c":"#E85D2A","w":2.2,"f":5,"a":7,"sp":1.4,"burst":true}]'::jsonb, 5) returning id)
insert into listen_tracks (proof_id, title, artist, why, position) select pf.id, t.* from pf, (values ('No Time for Caution', 'Hans Zimmer', 'The docking scene. Organ at full sail. The dynamic swing other tracks gossip about.', 1::int), ('Mars, the Bringer of War', 'Gustav Holst', 'The orchestra as a weapons system — col legno strings like knuckles on wood.', 2::int)) as t(title, artist, why, position);
commit;
